# =============================================================================
# Data classes
# =============================================================================

@dataclass(frozen=True)
class ProblemConfig:
    num_rows: int
    num_cols: int
    mass: int

    @property
    def size_name(self) -> str:
        return f"{self.num_rows}x{self.num_cols}"


@dataclass(frozen=True)
class ExactProblem:
    config: ProblemConfig
    row_margins: list[int]
    col_margins: list[int]
    states: np.ndarray
    flat_states: np.ndarray
    uniform: np.ndarray
    state_to_index: dict[tuple[int, ...], int]


# =============================================================================
# Margin generation
# =============================================================================

def card_like_margins(num_rows: int, num_cols: int, mass: int) -> tuple[list[int], list[int]]:
    if num_rows <= 0 or num_cols <= 0:
        raise ValueError("num_rows and num_cols must be positive")
    if mass < 0:
        raise ValueError("mass must be non-negative")

    rows = [0] * num_rows
    cols = [0] * num_cols

    # Rows: roughly balanced hand sizes.
    for i in range(mass):
        rows[i % num_rows] += 1

    # Columns: small bounded piles spread over card types in a pseudo-random order.
    remaining = mass

    for i in range(num_cols):
        if remaining == 0:
            break

        col = (i * 7 + 3) % num_cols

        if i % 6 == 0:
            cap = 0
        elif i % 6 == 1:
            cap = 1
        elif i % 6 == 2:
            cap = 2
        elif i % 6 == 3:
            cap = 3
        else:
            cap = 4

        amount = min(cap, remaining)
        cols[col] += amount
        remaining -= amount

    i = 0
    while remaining > 0:
        col = (i * 7 + 3) % num_cols
        cols[col] += 1
        remaining -= 1
        i += 1

    if sum(rows) != sum(cols):
        raise RuntimeError("Generated inconsistent margins")

    return rows, cols


# =============================================================================
# Exact distribution and Sinkhorn divergence
# =============================================================================

def state_key(state: np.ndarray) -> tuple[int, ...]:
    return tuple(np.asarray(state, dtype=np.int64).ravel().tolist())


def flatten_states(states: np.ndarray) -> np.ndarray:
    if states.ndim != 3:
        raise ValueError("states must have shape (num_states, rows, cols)")

    return states.reshape(states.shape[0], -1).astype(np.float64)


def rectangular_normalized_squared_cost(
    left_flat: np.ndarray,
    right_flat: np.ndarray,
    mass: int,
) -> np.ndarray:
    """
    Computes pairwise normalized squared Euclidean costs between two sets of states.

    Returns an array with shape:

        (len(left_flat), len(right_flat))

    This avoids constructing the much larger tensor:

        (len(left_flat), len(right_flat), num_cells)
    """
    if left_flat.ndim != 2 or right_flat.ndim != 2:
        raise ValueError("left_flat and right_flat must be 2D")
    if left_flat.shape[1] != right_flat.shape[1]:
        raise ValueError(
            f"State dimensions do not match: {left_flat.shape[1]} != {right_flat.shape[1]}"
        )
    if mass <= 0:
        raise ValueError("mass must be positive")

    left_norms = np.sum(left_flat * left_flat, axis=1)
    right_norms = np.sum(right_flat * right_flat, axis=1)

    cost = left_norms[:, None] + right_norms[None, :] - 2.0 * (left_flat @ right_flat.T)
    cost = np.maximum(cost, 0.0)

    return cost / float(mass * mass)


def get_exact_problem(config: ProblemConfig, cache_dir: Path) -> ExactProblem:
    cache_dir.mkdir(parents=True, exist_ok=True)

    row_margins, col_margins = card_like_margins(
        config.num_rows,
        config.num_cols,
        config.mass,
    )

    cache_path = cache_dir / f"exact_{config.size_name}_mass_{config.mass}.npz"

    if cache_path.exists():
        loaded = np.load(cache_path, allow_pickle=False)
        states = loaded["states"]
    else:
        states_list: list[np.ndarray] = []
        for state in tqdm(
            enumerate_states(row_margins, col_margins),
            desc=f"Enumerating exact states {config.size_name}, mass={config.mass}",
        ):
            states_list.append(np.asarray(state, dtype=np.int64))

            if len(states_list) > MAX_EXACT_STATES:
                raise RuntimeError(
                    f"Exact state count exceeded MAX_EXACT_STATES={MAX_EXACT_STATES}. "
                    f"Reduce MASS_BY_SIZE for {config.size_name}."
                )

        if not states_list:
            raise RuntimeError("Exact enumeration returned no states")

        states = np.stack(states_list, axis=0)

        np.savez_compressed(cache_path, states=states)

    uniform = np.ones(states.shape[0], dtype=np.float64) / states.shape[0]
    state_to_index = {state_key(state): idx for idx, state in enumerate(states)}
    flat_states = flatten_states(states)

    return ExactProblem(
        config=config,
        row_margins=row_margins,
        col_margins=col_margins,
        states=states,
        flat_states=flat_states,
        uniform=uniform,
        state_to_index=state_to_index,
    )


def empirical_distribution(samples: Iterable[np.ndarray], exact: ExactProblem) -> np.ndarray:
    probs = np.zeros(exact.states.shape[0], dtype=np.float64)

    count = 0
    for sample in samples:
        key = state_key(sample)

        try:
            idx = exact.state_to_index[key]
        except KeyError as exc:
            validate_matrix(sample, exact.row_margins, exact.col_margins)
            raise RuntimeError(
                "Sample was valid but not found in exact state index. "
                "This suggests inconsistent exact enumeration."
            ) from exc

        probs[idx] += 1.0
        count += 1

    if count == 0:
        raise ValueError("Cannot build empirical distribution from zero samples")

    probs /= count
    return probs

def empirical_support_distribution(
    samples: Iterable[np.ndarray],
    exact: ExactProblem,
) -> tuple[np.ndarray, np.ndarray]:
    """
    Returns:

        support_states:
            Unique sampled states, shape (num_unique, rows, cols)

        support_probs:
            Empirical probabilities over those unique states, shape (num_unique,)

    This is much smaller than the full exact-state empirical vector when the
    batch is small.
    """
    counts: dict[tuple[int, ...], int] = {}
    total = 0

    for sample in samples:
        key = state_key(sample)

        if key not in exact.state_to_index:
            validate_matrix(sample, exact.row_margins, exact.col_margins)
            raise RuntimeError(
                "Sample was valid but not found in exact state index. "
                "This suggests inconsistent exact enumeration."
            )

        counts[key] = counts.get(key, 0) + 1
        total += 1

    if total == 0:
        raise ValueError("Cannot build empirical distribution from zero samples")

    support = []
    probs = []

    for key, count in counts.items():
        idx = exact.state_to_index[key]
        support.append(exact.states[idx])
        probs.append(count / total)

    return np.stack(support, axis=0), np.array(probs, dtype=np.float64)

def sinkhorn_cost(
    a: np.ndarray,
    b: np.ndarray,
    cost: np.ndarray,
    epsilon: float = SINKHORN_EPSILON,
    max_iter: int = SINKHORN_MAX_ITER,
    tol: float = SINKHORN_TOL,
) -> float:
    """
    Entropically regularized OT cost using Sinkhorn scaling.

    This returns <P, C> for P = diag(u) K diag(v), K = exp(-C / epsilon).
    """
    if a.ndim != 1 or b.ndim != 1:
        raise ValueError("a and b must be 1D probability vectors")
    if cost.shape != (len(a), len(b)):
        raise ValueError(f"cost has shape {cost.shape}, expected {(len(a), len(b))}")
    if epsilon <= 0:
        raise ValueError("epsilon must be positive")
    if not np.isclose(a.sum(), 1.0):
        raise ValueError(f"a must sum to 1, got {a.sum()}")
    if not np.isclose(b.sum(), 1.0):
        raise ValueError(f"b must sum to 1, got {b.sum()}")

    k = np.exp(-cost / epsilon)
    k = np.maximum(k, np.finfo(np.float64).tiny)

    u = np.ones_like(a)
    v = np.ones_like(b)

    for _ in range(max_iter):
        old_u = u

        kv = k @ v
        kv = np.maximum(kv, np.finfo(np.float64).tiny)
        u = a / kv

        ktu = k.T @ u
        ktu = np.maximum(ktu, np.finfo(np.float64).tiny)
        v = b / ktu

        if np.max(np.abs(u - old_u)) < tol:
            break

    transport = (u[:, None] * k) * v[None, :]
    return float(np.sum(transport * cost))


def sinkhorn_divergence(a: np.ndarray, b: np.ndarray, cost: np.ndarray) -> float:
    """
    Sinkhorn divergence:

        S_e(a, b) = OT_e(a, b) - 0.5 OT_e(a, a) - 0.5 OT_e(b, b)

    This corrects the entropic self-bias and gives a more interpretable loss
    than the raw regularized transport cost.
    """
    ab = sinkhorn_cost(a, b, cost)
    aa = sinkhorn_cost(a, a, cost)
    bb = sinkhorn_cost(b, b, cost)
    return float(ab - 0.5 * aa - 0.5 * bb)


def distribution_loss(samples: Iterable[np.ndarray], exact: ExactProblem) -> float:
    """
    Computes a rectangular Sinkhorn loss between the empirical sample support
    and the exact uniform distribution.

    This avoids the full exact-by-exact cost matrix, which is too large for
    problems with tens of thousands of exact states.

    Note: this is the raw entropic OT cost, not the fully debiased Sinkhorn
    divergence, because the exact-uniform self-cost would require the same
    exact-by-exact matrix we are avoiding. For comparing step counts within the
    same problem, the omitted exact-uniform self-term is constant.
    """
    support_states, support_probs = empirical_support_distribution(samples, exact)
    support_flat = flatten_states(support_states)

    cost = rectangular_normalized_squared_cost(
        support_flat,
        exact.flat_states,
        exact.config.mass,
    )

    return sinkhorn_cost(
        support_probs,
        exact.uniform,
        cost,
        epsilon=SINKHORN_EPSILON,
        max_iter=SINKHORN_MAX_ITER,
        tol=SINKHORN_TOL,
    )


# =============================================================================
# Bootstrap
# =============================================================================

def bootstrap_mean_ci(
    values: np.ndarray,
    rng: np.random.Generator,
    replicates: int = BOOTSTRAP_REPLICATES,
    ci: float = BOOTSTRAP_CI,
) -> tuple[float, float, float]:
    if values.ndim != 1:
        raise ValueError("values must be 1D")
    if len(values) == 0:
        raise ValueError("Cannot bootstrap empty values")
    if replicates <= 0:
        raise ValueError("replicates must be positive")
    if not 0 < ci < 1:
        raise ValueError("ci must be between 0 and 1")

    means = np.empty(replicates, dtype=np.float64)

    for i in range(replicates):
        idxs = rng.integers(0, len(values), size=len(values))
        means[i] = values[idxs].mean()

    alpha = 1.0 - ci
    lower = float(np.quantile(means, alpha / 2.0))
    upper = float(np.quantile(means, 1.0 - alpha / 2.0))
    mean = float(values.mean())

    return mean, lower, upper


def bootstrap_distribution_loss_ci(
    samples: list[np.ndarray],
    exact: ExactProblem,
    rng: np.random.Generator,
    replicates: int = BOOTSTRAP_REPLICATES,
    ci: float = BOOTSTRAP_CI,
) -> tuple[float, float, float]:
    if not samples:
        raise ValueError("Cannot bootstrap empty samples")

    losses = np.empty(replicates, dtype=np.float64)

    for i in tqdm(range(replicates), desc="Bootstrapping initialization loss", leave=False):
        idxs = rng.integers(0, len(samples), size=len(samples))
        resampled = [samples[int(idx)] for idx in idxs]
        losses[i] = distribution_loss(resampled, exact)

    point = distribution_loss(samples, exact)

    alpha = 1.0 - ci
    lower = float(np.quantile(losses, alpha / 2.0))
    upper = float(np.quantile(losses, 1.0 - alpha / 2.0))

    return float(point), lower, upper


# =============================================================================
# File helpers / restartability
# =============================================================================

def config_paths(output_dir: Path, experiment: str, config: ProblemConfig, steps: int) -> tuple[Path, Path]:
    trial_dir = output_dir / experiment / config.size_name / f"mass_{config.mass}" / f"steps_{steps:04d}"
    return trial_dir, trial_dir / "results.csv"


def write_metadata(path: Path, metadata: dict[str, object]) -> None:
    with path.open("w", encoding="utf-8") as f:
        json.dump(metadata, f, indent=2, sort_keys=True)


def completed_csv(path: Path, expected_rows: int | None = None) -> bool:
    if not path.exists():
        return False

    try:
        df = pd.read_csv(path)
    except Exception:
        return False

    if "completed" not in df.columns:
        return False

    if not bool(df["completed"].all()):
        return False

    if expected_rows is not None and len(df) != expected_rows:
        return False

    return True


# =============================================================================
# Experiments
# =============================================================================

def experiment_configs() -> list[ProblemConfig]:
    configs: list[ProblemConfig] = []

    for size in MATRIX_SIZES:
        if size not in MASSES_BY_SIZE:
            raise ValueError(f"No masses configured for matrix size {size}")

        num_rows, num_cols = size

        for mass in MASSES_BY_SIZE[size]:
            configs.append(
                ProblemConfig(
                    num_rows=num_rows,
                    num_cols=num_cols,
                    mass=mass,
                )
            )

    return configs

def run_mixing_per_sample_trial(
    exact: ExactProblem,
    mixing_per_sample: int,
    output_dir: Path,
    seed: int,
) -> None:
    trial_dir, results_path = config_paths(
        output_dir,
        "mixing_per_sample",
        exact.config,
        mixing_per_sample,
    )

    if completed_csv(results_path, expected_rows=MIXING_TEST_NUM_BATCHES):
        return

    trial_dir.mkdir(parents=True, exist_ok=True)

    metadata = {
        "experiment": "mixing_per_sample",
        "config": asdict(exact.config),
        "row_margins": exact.row_margins,
        "col_margins": exact.col_margins,
        "num_exact_states": int(exact.states.shape[0]),
        "mixing_per_sample": mixing_per_sample,
        "num_batches": MIXING_TEST_NUM_BATCHES,
        "batch_size": MIXING_TEST_BATCH_SIZE,
        "total_samples": MIXING_TEST_TOTAL_SAMPLES,
        "initialization_steps_per_batch": MIXING_TEST_INITIALIZATION_STEPS,
        "sinkhorn_epsilon": SINKHORN_EPSILON,
        "seed": seed,
    }
    write_metadata(trial_dir / "metadata.json", metadata)

    rows: list[dict[str, object]] = []
    rng = np.random.default_rng(seed)

    iterator = tqdm(
        range(MIXING_TEST_NUM_BATCHES),
        desc=f"mix/sample {exact.config.size_name} mass={exact.config.mass} steps={mixing_per_sample}",
        leave=False,
    )

    for batch_idx in iterator:
        samples = generate_with_mixing(
            num_to_generate=MIXING_TEST_BATCH_SIZE,
            row_constraints=exact.row_margins,
            col_constraints=exact.col_margins,
            initial_mixing_steps=MIXING_TEST_INITIALIZATION_STEPS,
            mixing_per_sample=mixing_per_sample,
        )

        loss = distribution_loss(samples, exact)

        row = {
            "completed": True,
            "experiment": "mixing_per_sample",
            "size": exact.config.size_name,
            "num_rows": exact.config.num_rows,
            "num_cols": exact.config.num_cols,
            "mass": exact.config.mass,
            "num_exact_states": exact.states.shape[0],
            "mixing_per_sample": mixing_per_sample,
            "initialization_steps": MIXING_TEST_INITIALIZATION_STEPS,
            "batch_idx": batch_idx,
            "batch_size": MIXING_TEST_BATCH_SIZE,
            "loss": loss,
            "seed": seed,
        }
        rows.append(row)

        # Save as we go, so a crash loses at most one batch.
        pd.DataFrame(rows).to_csv(results_path, index=False)


def run_initialization_trial(
    exact: ExactProblem,
    initialization_steps: int,
    output_dir: Path,
    seed: int,
) -> None:
    trial_dir, results_path = config_paths(
        output_dir,
        "initialization",
        exact.config,
        initialization_steps,
    )

    if completed_csv(results_path, expected_rows=INITIALIZATION_TEST_NUM_BATCHES):
        return

    trial_dir.mkdir(parents=True, exist_ok=True)

    metadata = {
        "experiment": "initialization",
        "config": asdict(exact.config),
        "row_margins": exact.row_margins,
        "col_margins": exact.col_margins,
        "num_exact_states": int(exact.states.shape[0]),
        "initialization_steps": initialization_steps,
        "num_batches": INITIALIZATION_TEST_NUM_BATCHES,
        "batch_size": INITIALIZATION_TEST_BATCH_SIZE,
        "num_samples": INITIALIZATION_TEST_NUM_SAMPLES,
        "sinkhorn_epsilon": SINKHORN_EPSILON,
        "seed": seed,
        "ci_method": "bootstrap over batch losses",
    }
    write_metadata(trial_dir / "metadata.json", metadata)

    rng = np.random.default_rng(seed)

    rows: list[dict[str, object]] = []

    iterator = tqdm(
        range(INITIALIZATION_TEST_NUM_BATCHES),
        desc=f"init {exact.config.size_name} mass={exact.config.mass} steps={initialization_steps}",
        leave=False,
    )

    for batch_idx in iterator:
        samples: list[np.ndarray] = []

        for _ in range(INITIALIZATION_TEST_BATCH_SIZE):
            samples.extend(
                generate_with_mixing(
                    num_to_generate=1,
                    row_constraints=exact.row_margins,
                    col_constraints=exact.col_margins,
                    initial_mixing_steps=initialization_steps,
                    mixing_per_sample=0,
                )
            )

        loss = distribution_loss(samples, exact)

        row = {
            "completed": True,
            "experiment": "initialization",
            "size": exact.config.size_name,
            "num_rows": exact.config.num_rows,
            "num_cols": exact.config.num_cols,
            "mass": exact.config.mass,
            "num_exact_states": exact.states.shape[0],
            "initialization_steps": initialization_steps,
            "batch_idx": batch_idx,
            "batch_size": INITIALIZATION_TEST_BATCH_SIZE,
            "loss": loss,
            "seed": seed,
        }

        rows.append(row)

        # Save as we go, so a crash loses at most one batch.
        pd.DataFrame(rows).to_csv(results_path, index=False)


def run_all_trials(output_dir: Path) -> None:
    exact_cache_dir = output_dir / "exact_cache"

    configs = experiment_configs()

    exact_problems = [
        get_exact_problem(config, exact_cache_dir)
        for config in configs
    ]

    mixing_jobs: list[tuple[ExactProblem, int]] = [
        (exact, steps)
        for exact in exact_problems
        for steps in MIXING_STEPS
    ]

    initialization_jobs: list[tuple[ExactProblem, int]] = [
        (exact, steps)
        for exact in exact_problems
        for steps in INITIALIZATION_STEPS
    ]

    for job_idx, (exact, steps) in enumerate(tqdm(mixing_jobs, desc="Mixing-per-sample trials")):
        run_mixing_per_sample_trial(
            exact=exact,
            mixing_per_sample=steps,
            output_dir=output_dir,
            seed=RANDOM_SEED + 10_000 * job_idx,
        )

    for job_idx, (exact, steps) in enumerate(tqdm(initialization_jobs, desc="Initialization trials")):
        run_initialization_trial(
            exact=exact,
            initialization_steps=steps,
            output_dir=output_dir,
            seed=RANDOM_SEED + 1_000_000 + 10_000 * job_idx,
        )


# =============================================================================
# Aggregation and plotting
# =============================================================================

def summarize_steps_to_asymptote(
    summary: pd.DataFrame,
    step_col: str,
    output_path: Path,
    thresholds: list[float] | None = None,
) -> None:
    if thresholds is None:
        thresholds = [0.50, 0.80, 0.90, 0.95]

    rows: list[dict[str, object]] = []

    group_cols = ["size", "num_rows", "num_cols", "mass", "num_exact_states"]

    for keys, group in summary.groupby(group_cols, sort=True):
        group = group.sort_values(step_col)

        losses = group["mean_loss"].to_numpy(dtype=np.float64)
        steps = group[step_col].to_numpy(dtype=np.int64)

        initial_loss = float(losses[0])
        min_loss = float(np.min(losses))

        for threshold in thresholds:
            target = min_loss + (initial_loss - min_loss) * (1.0 - threshold)

            reached = group[group["mean_loss"] <= target]

            if reached.empty:
                first_step = None
            else:
                first_step = int(reached[step_col].iloc[0])

            row: dict[str, object] = dict(zip(group_cols, keys))
            row.update(
                {
                    "step_col": step_col,
                    "threshold": threshold,
                    "target_loss": target,
                    "initial_loss": initial_loss,
                    "min_loss": min_loss,
                    "first_step": first_step,
                }
            )
            rows.append(row)

    pd.DataFrame(rows).to_csv(output_path, index=False)

def read_experiment_results(output_dir: Path, experiment: str) -> pd.DataFrame:
    paths = list((output_dir / experiment).glob("**/results.csv"))

    if not paths:
        raise FileNotFoundError(f"No result CSVs found for experiment {experiment}")

    frames = []
    for path in paths:
        df = pd.read_csv(path)
        if "completed" in df.columns and bool(df["completed"].all()):
            frames.append(df)

    if not frames:
        raise RuntimeError(f"No completed result CSVs found for experiment {experiment}")

    return pd.concat(frames, ignore_index=True)


def summarize_mixing_results(df: pd.DataFrame) -> pd.DataFrame:
    rows: list[dict[str, object]] = []
    rng = np.random.default_rng(RANDOM_SEED + 424242)

    group_cols = ["size", "num_rows", "num_cols", "mass", "mixing_per_sample", "num_exact_states"]

    for keys, group in df.groupby(group_cols, sort=True):
        losses = group["loss"].to_numpy(dtype=np.float64)
        mean, ci_low, ci_high = bootstrap_mean_ci(losses, rng)

        row: dict[str, object] = dict(zip(group_cols, keys))
        row.update(
            {
                "mean_loss": mean,
                "loss_ci_low": ci_low,
                "loss_ci_high": ci_high,
                "num_batches": len(group),
            }
        )
        rows.append(row)

    return pd.DataFrame(rows).sort_values(["num_rows", "num_cols", "mixing_per_sample"])


