def plot_loss_by_steps(
    summary: pd.DataFrame,
    step_col: str,
    output_path: Path,
    title: str,
    x_label: str,
) -> None:
    sns.set_theme(style="darkgrid", context="talk")

    # Average over masses for each size/step.
    averaged_rows: list[dict[str, object]] = []
    rng = np.random.default_rng(RANDOM_SEED + 777_777)

    for (size, step), group in summary.groupby(["size", step_col], sort=True):
        losses = group["mean_loss"].to_numpy(dtype=np.float64)

        mean, ci_low, ci_high = bootstrap_mean_ci(losses, rng)

        averaged_rows.append(
            {
                "size": size,
                step_col: step,
                "mean_loss": mean,
                "loss_ci_low": ci_low,
                "loss_ci_high": ci_high,
                "num_masses": len(group),
                "min_mass": int(group["mass"].min()),
                "max_mass": int(group["mass"].max()),
                "min_exact_states": int(group["num_exact_states"].min()),
                "max_exact_states": int(group["num_exact_states"].max()),
            }
        )

    averaged = pd.DataFrame(averaged_rows)

    sizes = sorted(averaged["size"].unique())
    fig, axes = plt.subplots(
        len(sizes),
        1,
        figsize=(15, 5 * len(sizes)),
        sharex=True,
        squeeze=False,
    )

    for ax, size in zip(axes[:, 0], sizes):
        subset = averaged[averaged["size"] == size].sort_values(step_col)

        if subset.empty:
            ax.set_visible(False)
            continue

        x = subset[step_col].to_numpy(dtype=np.float64)
        y = subset["mean_loss"].to_numpy(dtype=np.float64)
        low = subset["loss_ci_low"].to_numpy(dtype=np.float64)
        high = subset["loss_ci_high"].to_numpy(dtype=np.float64)

        ax.plot(x, y, marker="o", label=f"{size} mean over masses")
        ax.fill_between(
            x,
            low,
            high,
            alpha=0.25,
            label=f"{int(BOOTSTRAP_CI * 100)}% CI over masses",
        )

        min_loss = float(np.min(y))
        initial_loss = float(y[0])

        for p in [0.50, 0.80, 0.90, 0.95]:
            threshold = min_loss + (initial_loss - min_loss) * (1.0 - p)
            ax.axhline(
                threshold,
                color="black",
                linestyle=":",
                linewidth=1.5,
                alpha=0.55,
            )
            ax.text(
                x[-1],
                threshold,
                f" {int(p * 100)}%",
                va="center",
                ha="left",
                fontsize=10,
                color="black",
            )

        num_masses = int(subset["num_masses"].max())
        min_mass = int(subset["min_mass"].min())
        max_mass = int(subset["max_mass"].max())
        min_states = int(subset["min_exact_states"].min())
        max_states = int(subset["max_exact_states"].max())

        ax.set_title(
            f"{size}, averaged over {num_masses} masses "
            f"({min_mass}–{max_mass}); states {min_states}–{max_states}"
        )
        ax.set_ylabel("Mean Sinkhorn divergence")
        ax.set_xscale("log")
        ax.set_ylabel("Mean Sinkhorn divergence")
        ax.set_xscale("log")

        step_values = sorted(averaged[step_col].unique())
        ax.set_xticks(step_values)
        ax.set_xticklabels([str(int(x)) for x in step_values], rotation=45, ha="right")

        ax.legend(loc="best")
        ax.legend(loc="best")

    axes[-1, 0].set_xlabel(x_label)
    fig.suptitle(title, y=1.02)
    fig.tight_layout()
    fig.savefig(output_path, dpi=220, bbox_inches="tight")
    plt.close(fig)


