def add_within_curve_normalized_loss(
    summary: pd.DataFrame,
    step_col: str,
) -> pd.DataFrame:
    """
    Adds normalized loss columns within each (size, mass) curve.

    normalized_excess_loss:
        1.0 at the first tested step count.
        0.0 at the best observed loss for that size/mass.

    normalized_progress:
        0.0 at the first tested step count.
        1.0 at the best observed loss for that size/mass.
    """
    output = summary.copy()

    output["normalized_excess_loss"] = np.nan
    output["normalized_progress"] = np.nan

    group_cols = ["size", "mass"]

    for _, idxs in output.groupby(group_cols).groups.items():
        group = output.loc[idxs].sort_values(step_col)

        losses = group["mean_loss"].to_numpy(dtype=np.float64)

        initial_loss = float(losses[0])
        min_loss = float(np.min(losses))
        denom = initial_loss - min_loss

        if denom <= 0:
            normalized_excess = np.zeros_like(losses)
            normalized_progress = np.ones_like(losses)
        else:
            normalized_excess = (losses - min_loss) / denom
            normalized_progress = 1.0 - normalized_excess

        output.loc[group.index, "normalized_excess_loss"] = normalized_excess
        output.loc[group.index, "normalized_progress"] = normalized_progress

    return output

def plot_normalized_progress_by_mass_for_each_size(
    summary: pd.DataFrame,
    step_col: str,
    output_path: Path,
    title: str,
    x_label: str,
) -> None:
    sns.set_theme(style="darkgrid", context="talk")

    normalized = add_within_curve_normalized_loss(summary, step_col)

    sizes = sorted(normalized["size"].unique())

    fig, axes = plt.subplots(
        len(sizes),
        1,
        figsize=(15, 5 * len(sizes)),
        sharex=True,
        sharey=True,
        squeeze=False,
    )

    for ax, size in zip(axes[:, 0], sizes):
        size_subset = normalized[normalized["size"] == size].copy()

        if size_subset.empty:
            ax.set_visible(False)
            continue

        masses = sorted(size_subset["mass"].unique())
        palette = dict(zip(masses, sns.color_palette("viridis", n_colors=len(masses))))

        for mass in masses:
            subset = size_subset[size_subset["mass"] == mass].sort_values(step_col)

            ax.plot(
                subset[step_col],
                subset["normalized_progress"],
                marker="o",
                linewidth=2,
                color=palette[mass],
                label=f"mass={mass}, states={int(subset['num_exact_states'].iloc[0])}",
            )

        for p in [0.50, 0.80, 0.90, 0.95]:
            ax.axhline(
                p,
                color="black",
                linestyle=":",
                linewidth=1.5,
                alpha=0.55,
            )
            ax.text(
                float(size_subset[step_col].max()),
                p,
                f" {int(p * 100)}%",
                va="center",
                ha="left",
                fontsize=10,
                color="black",
            )

        ax.set_title(f"{size}: normalized progress toward observed asymptote")
        ax.set_ylabel("Normalized progress")
        ax.set_xscale("log")
        ax.set_title(f"{size}: normalized progress toward observed asymptote")
        ax.set_ylabel("Normalized progress")
        ax.set_xscale("log")

        step_values = sorted(normalized[step_col].unique())
        ax.set_xticks(step_values)
        ax.set_xticklabels([str(int(x)) for x in step_values], rotation=45, ha="right")

        ax.set_ylim(-0.05, 1.05)
        ax.legend(loc="best", fontsize=9)
        ax.set_ylim(-0.05, 1.05)
        ax.legend(loc="best", fontsize=9)

    axes[-1, 0].set_xlabel(x_label)

    fig.suptitle(title, y=1.02)
    fig.tight_layout()
    fig.savefig(output_path, dpi=220, bbox_inches="tight")
    plt.close(fig)

def plot_normalized_combined_loss_by_steps(
    summary: pd.DataFrame,
    step_col: str,
    output_path: Path,
    title: str,
    x_label: str,
) -> None:
    """
    Normalize each (size, mass) curve within itself, then average over masses.

    normalized_progress:
        0.0 = loss at the first tested step count
        1.0 = best/asymptotic observed loss for that size/mass curve

    The final plot has one line per matrix size, with bootstrap CIs over masses.
    """
    sns.set_theme(style="darkgrid", context="talk")

    normalized = add_within_curve_normalized_loss(summary, step_col)

    rows: list[dict[str, object]] = []
    rng = np.random.default_rng(RANDOM_SEED + 888_888)

    for (size, step), group in normalized.groupby(["size", step_col], sort=True):
        values = group["normalized_progress"].to_numpy(dtype=np.float64)

        mean, ci_low, ci_high = bootstrap_mean_ci(values, rng)

        rows.append(
            {
                "size": size,
                step_col: step,
                "mean_progress": mean,
                "progress_ci_low": ci_low,
                "progress_ci_high": ci_high,
                "num_masses": len(group),
                "min_mass": int(group["mass"].min()),
                "max_mass": int(group["mass"].max()),
                "min_exact_states": int(group["num_exact_states"].min()),
                "max_exact_states": int(group["num_exact_states"].max()),
            }
        )

    averaged = pd.DataFrame(rows).sort_values(["size", step_col])

    plt.figure(figsize=(15, 10))

    sizes = sorted(averaged["size"].unique())
    palette = dict(zip(sizes, sns.color_palette("viridis", n_colors=len(sizes))))

    for size in sizes:
        subset = averaged[averaged["size"] == size].sort_values(step_col)

        x = subset[step_col].to_numpy(dtype=np.float64)
        y = subset["mean_progress"].to_numpy(dtype=np.float64)
        low = subset["progress_ci_low"].to_numpy(dtype=np.float64)
        high = subset["progress_ci_high"].to_numpy(dtype=np.float64)

        label = (
            f"{size} "
            f"(masses {int(subset['min_mass'].min())}–{int(subset['max_mass'].max())})"
        )

        plt.plot(
            x,
            y,
            marker="o",
            linewidth=2.5,
            color=palette[size],
            label=label,
        )

        plt.fill_between(
            x,
            low,
            high,
            color=palette[size],
            alpha=0.18,
        )

    for p in [0.50, 0.80, 0.90, 0.95]:
        plt.axhline(
            p,
            color="black",
            linestyle=":",
            linewidth=1.5,
            alpha=0.55,
        )
        plt.text(
            float(averaged[step_col].max()),
            p,
            f" {int(p * 100)}%",
            va="center",
            ha="left",
            fontsize=10,
            color="black",
        )

    step_values = sorted(averaged[step_col].unique())

    ax = plt.gca()
    ax.set_xscale("log")
    ax.set_xticks(step_values)
    ax.set_xticklabels([str(int(x)) for x in step_values], rotation=45, ha="right")

    ax.set_ylim(-0.05, 1.05)
    ax.set_xlabel(x_label)
    ax.set_ylabel("Mean normalized progress")
    ax.set_title(title)
    ax.legend(loc="best")

    plt.tight_layout()
    plt.savefig(output_path, dpi=220, bbox_inches="tight")
    plt.close()


def write_summaries_and_plots(output_dir: Path) -> None:
    plots_dir = output_dir / "plots"
    plots_dir.mkdir(parents=True, exist_ok=True)

    mixing_raw = read_experiment_results(output_dir, "mixing_per_sample")
    initialization_raw = read_experiment_results(output_dir, "initialization")

    mixing_summary = summarize_mixing_results(mixing_raw)
    initialization_summary = summarize_initialization_results(initialization_raw)

    mixing_raw.to_csv(output_dir / "mixing_per_sample_raw.csv", index=False)
    initialization_raw.to_csv(output_dir / "initialization_raw.csv", index=False)
    mixing_summary.to_csv(output_dir / "mixing_per_sample_summary.csv", index=False)
    initialization_summary.to_csv(output_dir / "initialization_summary.csv", index=False)

    plot_loss_by_steps(
        mixing_summary,
        step_col="mixing_per_sample",
        output_path=plots_dir / "mixing_per_sample_loss.png",
        title="Mixing-per-sample test\nBatch loss against exact uniform distribution",
        x_label="Mixing steps between samples",
    )

    plot_loss_by_steps(
        initialization_summary,
        step_col="initialization_steps",
        output_path=plots_dir / "initialization_loss.png",
        title="Initialization test\nIndependent sample loss against exact uniform distribution",
        x_label="Initialization mixing steps",
    )

    summarize_steps_to_asymptote(
        mixing_summary,
        step_col="mixing_per_sample",
        output_path=output_dir / "mixing_steps_to_asymptote.csv",
    )

    summarize_steps_to_asymptote(
        initialization_summary,
        step_col="initialization_steps",
        output_path=output_dir / "initialization_steps_to_asymptote.csv",
    )

    plot_mixing_loss_by_mass_for_each_size(
        mixing_summary,
        plots_dir,
    )

    plot_initialization_loss_by_mass_for_each_size(
        initialization_summary,
        plots_dir,
    )

    plot_normalized_progress_by_mass_for_each_size(
        mixing_summary,
        step_col="mixing_per_sample",
        output_path=plots_dir / "mixing_normalized_progress_by_mass.png",
        title="Mixing-per-sample normalized progress\nEach curve is normalized within its own size/mass setting",
        x_label="Mixing steps between samples",
    )

    plot_normalized_progress_by_mass_for_each_size(
        initialization_summary,
        step_col="initialization_steps",
        output_path=plots_dir / "initialization_normalized_progress_by_mass.png",
        title="Initialization normalized progress\nEach curve is normalized within its own size/mass setting",
        x_label="Initialization mixing steps",
    )

    plot_normalized_combined_loss_by_steps(
        mixing_summary,
        step_col="mixing_per_sample",
        output_path=plots_dir / "mixing_normalized_combined_by_size.png",
        title=(
            "Mixing-per-sample normalized progress by matrix size\n"
            "Each line averages over masses after within-mass normalization"
        ),
        x_label="Mixing steps between samples",
    )

    plot_normalized_combined_loss_by_steps(
        initialization_summary,
        step_col="initialization_steps",
        output_path=plots_dir / "initialization_normalized_combined_by_size.png",
        title=(
            "Initialization normalized progress by matrix size\n"
            "Each line averages over masses after within-mass normalization"
        ),
        x_label="Initialization mixing steps",
    )

# =============================================================================
# CLI
# =============================================================================

def main() -> None:
    parser = argparse.ArgumentParser(
        description="Run small exact-distribution mass-mixing experiments."
    )

    parser.add_argument(
        "--output-dir",
        type=Path,
        default=OUTPUT_DIR,
        help=f"Output directory. Default: {OUTPUT_DIR}",
    )

    parser.add_argument(
        "--plots-only",
        action="store_true",
        help="Only regenerate summaries and plots from existing results.",
    )

    args = parser.parse_args()

    args.output_dir.mkdir(parents=True, exist_ok=True)

    if not args.plots_only:
        run_all_trials(args.output_dir)

    write_summaries_and_plots(args.output_dir)

    print(f"Wrote experiment results to: {args.output_dir}")
    print(f"Wrote plots to: {args.output_dir / 'plots'}")


if __name__ == "__main__":
    main()